"""
MKT Context Commentary — Esther chapters 6–10
Run: python3 scripts/zc-context-esther-6-10.py

Key contextual threads:
- Ch 6: Providential reversal through royal insomnia; pur structure inverted before the pur is cast
- Ch 7: Esther's petition mirrors the death-warrant language; Persian face-covering = execution signal
- Ch 8: Irrevocability of Persian law forces counter-decree rather than cancellation (cf. Dan 6)
  Mordecai robed in blue/white = Persian royal investiture; mityyahadim = first use of "to Judaize"
- Ch 9: Three times "no hand on the plunder" — completes what Saul failed to do (1 Sam 15)
  Purim = Persian pur glossed with Hebrew goral; first festival instituted by community decree not Torah
- Ch 10: Mordecai as "second" echoes Joseph/Daniel diaspora pattern; seeks good of his people
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ESTHER = {
  "6": {
    "1": "<p>The king&#8217;s insomnia is the hinge on which the entire narrative turns. <em>Nāḏᵃḏāh šᵉnat hammelek</em> — &#8220;the sleep of the king fled&#8221; — is the book&#8217;s most transparent window onto divine providence. Herodotus and other ancient sources document the practice of reading royal records aloud to monarchs; the Persian court maintained detailed archives of services rendered to the crown. That the very chronicle containing Mordecai&#8217;s unrewarded service is selected on this particular night, hours before Haman arrives to request his execution, is the story&#8217;s central miracle — presented without supernatural apparatus.</p>",
    "2": "<p>The record of Mordecai&#8217;s exposure of the Bigthana/Teresh assassination plot (Esther 2:21-23) reappears at precisely the moment it can save him. The five-year gap between the event and the reading (if the dating is ca. 483-479 BCE) is itself significant: rewards in Persian royal practice were not merely symbolic but material — horses, robes, public proclamation — and their delay creates a debt the king now feels compelled to honor. The chronicle system that Haman had hoped to use against the Jews (the decree in 3:12-14) now becomes the instrument of his undoing.</p>",
    "3": "<p>&#8220;Nothing has been done for him&#8221; — the attendants&#8217; answer registers the oversight that the narrative has been building toward since 2:23. In Persian court protocol, rewarding loyalty was both an ethical obligation and a political necessity: failure to reward a benefactor signaled the king&#8217;s unreliability. The king&#8217;s urgency to remedy this immediately — &#8220;Who is in the court?&#8221; — reflects this protocol. The dramatic irony is that Haman, present to seek Mordecai&#8217;s execution, will be conscripted to honor him.</p>",
    "4": "<p>Haman has arrived at dawn (<em>ḥᵃṣar bêṯ hammelek haḥîṣônāh</em> — the outer court) specifically to request permission to hang Mordecai on the fifty-cubit gallows just constructed (5:14). The narrative compression is deliberate: the gallows stands ready, Haman&#8217;s request is formed, and the king&#8217;s question about honoring Mordecai arrives simultaneously. The two intentions — execution and exaltation — collide in the same court at the same moment.</p>",
    "5": "<p>&#8220;Bring him in&#8221; — the king summons Haman without informing him why, so Haman enters expecting to make his request and instead receives one. The narrative withholds Haman&#8217;s reason for coming, drawing the reader through the scene with full knowledge that Haman lacks. The eunuch&#8217;s role as intermediary (&#8220;The king&#8217;s servants told him, &#8216;Haman is standing in the court&#8217;&#8221;) reflects the layered access protocol of Persian royal chambers.</p>",
    "6": "<p>&#8220;Haman thought to himself, &#8216;Whom would the king wish to honor more than me?&#8217;&#8221; — <em>ʾemar bᵉlibbô</em> (said in his heart) is the narrator&#8217;s technique for revealing private assumption without quotation marks. The question Haman asks himself (&#8220;for whom would the king want to do this more than me?&#8221;) is answered in the very next verse by the king&#8217;s actual object: Mordecai. The Hebrew uses the identical phrase structure, creating a verbal irony that is structural, not merely accidental.</p>",
    "7": "<p>Haman begins his elaborately self-serving answer by framing it as counsel about the honoree: &#8220;For the man the king wishes to honor—&#8221; The rhetorical move delays naming the recipient to allow Haman to stack as many royal honors as possible — robes, horse, crown, public proclamation. Each element is a component of royal investiture in Persian court ceremonial, attested in reliefs from Persepolis. Haman is essentially designing his own coronation.</p>",
    "8": "<p>The elements Haman specifies — <em>lᵉḇûš malkûṯ</em> (royal garments), <em>sûs ʾᵃšer rāḵaḇ ʿālāyw hammelek</em> (the horse the king rides), and the royal crown placed on the horse&#8217;s head — describe the highest visible markers of Persian royal status. The crown on the horse&#8217;s head is disputed: some read it as a crest or emblem worn by the king&#8217;s personal mount rather than the royal diadem itself. Persian reliefs show royal horses with elaborate headgear. Haman is requesting a visual simulation of royalty itself.</p>",
    "9": "<p>&#8220;Then let this robe and horse be handed over to one of the king&#8217;s most distinguished nobles&#8221; — Haman places himself in the role of the noble who would conduct the ceremony, imagining himself both the recipient and the herald. The proclamation formula he proposes — &#8220;This is what is done for the man whom the king wishes to honor&#8221; — is a public declaration that would bind the king&#8217;s honor to this man permanently. Haman is designing an irreversible public statement of royal favor for himself.</p>",
    "10": "<p>&#8220;Hurry — take the robe and the horse exactly as you have described, and do all this for Mordecai the Jew, who is sitting at the king&#8217;s gate. Do not neglect (<em>ʾal-tapēl</em>) a single thing of all you have spoken.&#8221; The king&#8217;s instruction binds Haman to the full protocol he himself specified; the phrase &#8220;do not neglect a single thing&#8221; prevents Haman from diminishing the honor. The identification of Mordecai as &#8220;the Jew sitting at the king&#8217;s gate&#8221; — the same description Haman used in his complaint (5:13) — is the verbal pivot of the reversal.</p>",
    "11": "<p>Haman takes the robe and horse, dresses Mordecai, leads him through the city square on horseback, and proclaims before him: &#8220;This is what is done for the man whom the king wishes to honor!&#8221; The physical intimacy of the act — Haman dressing Mordecai — is the ultimate humiliation. The public proclamation that Haman had designed for his own glory is now delivered by him for his enemy, in the streets of Susa, before all who had watched the Jews&#8217; mourning (4:1-3). The same crowds who saw Mordecai in sackcloth now see him in royal robes.</p>",
    "12": "<p>&#8220;Mordecai returned to the king&#8217;s gate, while Haman rushed home in mourning, his head covered.&#8221; The covered head (<em>ḥāpûy rōʾš</em>) is a Persian gesture of grief and shame, paralleled in 2 Samuel 15:30 where David covers his head fleeing Jerusalem. Mordecai&#8217;s immediate return to the gate — his post, his station — signals that the honor has not changed his character or his role. Haman&#8217;s covered head anticipates the physical covering of his face at 7:8 when the king signals his execution.</p>",
    "13": "<p>Zeresh and the advisors now reverse their earlier counsel: in 5:14 they had suggested the gallows; now they read the pattern of events as a portent of inevitable failure. &#8220;If Mordecai is of Jewish seed (<em>mizzera&#x60; hayyᵉhûḏîm</em>), before whom you have begun to fall, you will surely fall before him — you cannot prevail against him.&#8221; The pagan recognition of Jewish providential protection is a recurring motif in Scripture (Rahab in Josh 2:9-11; Naaman&#8217;s servants; the Ninevites); here it comes from within Haman&#8217;s own household, too late to redirect his course.</p>",
    "14": "<p>The chamberlains arrive while Haman is still receiving counsel from his wife and advisors, hurrying him to Esther&#8217;s banquet. The transition has no gap: Haman has just heard that he will fall, and he is immediately escorted to the scene of that fall. The narrative compresses time to prevent any possibility of Haman adjusting his strategy; providence and human haste work together.</p>"
  },
  "7": {
    "1": "<p>The king and Haman attend Esther&#8217;s second banquet. The first banquet (5:4-8) had generated only a delayed petition; now the moment of revelation is at hand. Persian royal banquets followed a ritual sequence of courses, and the &#8220;banquet of wine&#8221; (<em>mišᵉtēh hayyayin</em>) marks the after-dinner phase when petitions were traditionally made. The twice-repeated offer (5:3, 6) is now repeated a third time in 7:2 — the tripling intensifies the formal obligation to answer.</p>",
    "2": "<p>&#8220;What is your petition, Queen Esther? It shall be granted to you. And what is your request? Even up to half the kingdom, it shall be fulfilled.&#8221; The formulaic offer has been repeated three times; Esther&#8217;s strategy of delay — building suspense and royal commitment — has created the maximum possible obligation. The king&#8217;s repetition of the full formula signals that his patience is at its limit and Esther must now speak.</p>",
    "3": "<p>&#8220;Let my life be given me at my petition, and my people at my request.&#8221; Esther&#8217;s petition begins with herself (<em>napšî...ʿammî</em>) — her own life before her people&#8217;s — which makes the threat personal and immediate for the king. The phrasing shifts from the abstract &#8220;request&#8221; of her delay banquets to the concrete stakes of survival. The phrase <em>ʾim-māṣāʾṯî ḥēn bᵉʿênê hammelek</em> (if I have found favor in the king&#8217;s eyes) echoes the formula of covenantal appeal throughout the OT.</p>",
    "4": "<p>&#8220;For we have been sold (<em>nimkarᵉnû</em>) — I and my people — to be destroyed, to be killed, and to be annihilated.&#8221; Esther uses the exact triple verb formula (<em>lᵉhašmîḏ lahᵃrōḡ ûlᵉʾabbēḏ</em>) from the original decree (3:13), connecting her petition directly to Haman&#8217;s language. The word <em>nimkarᵉnû</em> (sold) implies that money changed hands — the ten thousand talents of silver Haman offered the king (3:9) — framing the Jews as commodities rather than citizens. &#8220;Had we only been sold as slaves, I would have held my tongue&#8221; — enslavement is tolerable; annihilation is not; the distinction defines the threshold of intercession.</p>",
    "5": "<p>&#8220;Who is he, and where is he, who has presumed in his heart (<em>ʾᵃšer mᵉlāʾô libbô</em>) to do this?&#8221; The idiom &#8220;whose heart is full to do&#8221; implies moral presumption — the fullness of heart that oversteps its authority. The king&#8217;s question is dramatic: he has signed the decree, accepted the silver, and yet asks who is responsible — either he has forgotten, or he has not connected the decree to its application to his own queen.</p>",
    "6": "<p>&#8220;The adversary and enemy (<em>ʾîš ṣar wᵉʾôyēḇ</em>) is this wicked Haman!&#8221; The double epithet — <em>ṣar</em> (adversary/oppressor) and <em>ʾôyēḇ</em> (enemy) — precisely mirrors the description of Israel&#8217;s covenant enemies in the Psalms and Lamentations. Haman&#8217;s terror before both the king and queen signals the complete collapse of his position; the man who minutes ago was being honored in the streets now stands accused before the throne that authorized his decree.</p>",
    "7": "<p>The king withdraws to the palace garden — a standard Persian royal practice of deliberation before judgment. Haman recognizes that the king has decided his fate (<em>kî-kāltāh ʾēlāyw hārāʿāh min-hammelek</em> — &#8220;evil was determined against him by the king&#8221;) and falls on the couch where Esther reclines to plead for his life. The act of a man falling on a woman&#8217;s couch in the royal inner chambers was a severe breach of protocol — access to the queen&#8217;s person was as restricted as access to the king.</p>",
    "8": "<p>The king returns to find Haman on Esther&#8217;s couch: &#8220;Will he even assault the queen (<em>hᵃgam likḇôš ʾeṯ-hammalᵉkāh</em>) in my own house?&#8221; The king misreads prostration as assault — whether deliberately or genuinely is unclear. The word <em>likḇôš</em> (to subdue/assault) is strong and legal. As the words leave the king&#8217;s mouth, attendants cover Haman&#8217;s face — the Persian signal of a condemned man, documented in Herodotus and Plutarch: once the royal face is averted and the prisoner&#8217;s face covered, the death sentence is irrevocable.</p>",
    "9": "<p>Harbonah, one of the king&#8217;s eunuchs, volunteers the information about the gallows: &#8220;There is also the gallows, fifty cubits high, that Haman made for Mordecai, who spoke up for the king&#8221; — reminding the king that Mordecai, the man just publicly honored, had been scheduled for execution by this same Haman. The eunuch&#8217;s intervention is providentially timed and politically acute; his epithet for Mordecai — &#8220;who spoke up for the king&#8221; — reactivates the chronicle narrative from chapter 6.</p>",
    "10": "<p>&#8220;So they hanged Haman on the gallows he had prepared for Mordecai, and the king&#8217;s wrath was appeased.&#8221; The irony is structural: the fifty-cubit height intended to maximize public shame for Mordecai now maximizes public shame for Haman. The verb <em>wattiškaḵ ḥᵃmaṯ hammelek</em> — &#8220;the king&#8217;s wrath subsided/was relieved&#8221; — uses the same root as the wrath provoked by Vashti in 1:12; the tension opened in chapter 1 is resolved here. The gallows as self-executed judgment enacts the proverb pattern of Prov 26:27.</p>"
  },
  "8": {
    "1": "<p>&#8220;That same day (<em>bayyôm hahûʾ</em>) King Ahasuerus gave Queen Esther the estate of Haman.&#8221; The confiscation of a condemned official&#8217;s property by the crown is standard Persian legal procedure, attested in the Fortification Tablets from Persepolis. Esther receives Haman&#8217;s estate — the material reversal accompanies the political one. Mordecai&#8217;s appearance before the king marks his formal introduction to the court; Esther reveals his relationship to her, integrating the two halves of the story that had been kept separate.</p>",
    "2": "<p>The king removes the signet ring from Haman&#8217;s hand (having recovered it — Haman had presumably been wearing it as the authorized agent of the decree) and gives it to Mordecai. The signet ring is the instrument of legal authority in the Persian system: whatever it seals is the king&#8217;s command. The ring that authorized the genocide of the Jews is now in the hands of a Jew. Esther appoints Mordecai over Haman&#8217;s estate — the administration of the condemned man&#8217;s household passes to his intended victim.</p>",
    "3": "<p>Esther&#8217;s second intercession for her people requires approaching the king again, falling at his feet and weeping. The combination of physical prostration (<em>tippōl lipnê raglāyw</em>), weeping (<em>wattēḇḵ</em>), and supplication (<em>wattitḥannen</em>) is the full posture of covenant pleading, paralleling Moses&#8217; intercession after the golden calf (Exod 32:11-13) and David&#8217;s prayer in Psalm 51. The &#8220;evil scheme of Haman the Agagite and his plot which he had devised against the Jews&#8221; is identified by name even after Haman&#8217;s execution — the decree itself is still active and must be addressed.</p>",
    "4": "<p>The king again extends the golden scepter — the third use of this gesture in the book (5:2; earlier in ch. 8). The first was survival (5:2); the second was petition (5:3); the third is renewal of the right to speak. Esther rises from prostration to standing — the movement from suppliant to advocate. The throne-room scene is repeated with slightly different stakes: now it is not about personal survival but about the survival of a people.</p>",
    "5": "<p>&#8220;If it pleases the king, and if I have found favour in his sight, and if the matter seems right to the king, and if I am pleasing in his eyes&#8221; — Esther uses four conditional clauses of deference (<em>ʾim-ṭôḇ ʿal-hammelek... wᵉʾim-māṣāʾṯî ḥēn... wᵉkāšēr... wᵉṭôḇāh ʾᵃnî</em>) before making her request. The accumulation is a rhetorical technique of maximizing the appearance of submission to increase the likelihood of a favorable response. Persian court petitions required elaborate formulaic deference.</p>",
    "6": "<p>&#8220;For how can I endure to see the disaster that will come upon my people? How can I bear to see the destruction of my kindred?&#8221; Esther&#8217;s emotional appeal is not rhetorical but existential: she is asking the king to understand the unbearability of watching one&#8217;s people destroyed. The double question (<em>ʾêḵāh ʾûḵal wᵉrāʾîṯî</em>) mirrors the lament form of Lamentations and Psalms — the language of covenant grief. Her request is grounded not in legal argument but in the king&#8217;s capacity for empathy with her distress.</p>",
    "7": "<p>The king&#8217;s response is not a new decree but an authorization: he reminds Esther and Mordecai that he has already given Haman&#8217;s estate to Esther and hanged Haman, then charges them: &#8220;Now write on behalf of the Jews as you see fit, in the king&#8217;s name, and seal it with the king&#8217;s signet ring.&#8221; The delegation of legislative authority to Esther and Mordecai is remarkable — the king essentially cedes the composition of the counter-decree to its intended beneficiaries, a level of trust that reflects Mordecai&#8217;s new position.</p>",
    "8": "<p>&#8220;For no decree written in the king&#8217;s name and sealed with the king&#8217;s ring can be revoked&#8221; — the irrevocability of Persian royal decrees is a structural constraint that runs through both the book of Esther and Daniel (Dan 6:8, 12, 15). The Medes-and-Persians law principle means that the original genocidal decree cannot be cancelled; it can only be countermanded by an equally authoritative decree permitting the Jews to defend themselves. The legal impossibility of revocation is the narrative tension that makes the counter-decree necessary rather than optional.</p>",
    "9": "<p>The scribes are summoned on the twenty-third day of the third month — Sivan — approximately nine months before the thirteenth of Adar (9:1). This interval is intentional: the Jews must have time to organize, arm, and communicate the counter-decree across all 127 provinces. The decree is issued in every language — &#8220;according to the script of every province and the language of every people, and also to the Jews in their script and language&#8221; — an administrative detail that emphasizes the Persian empire&#8217;s multilingual bureaucracy and the Jews&#8217; distinct identity within it.</p>",
    "10": "<p><em>Hārākkûš ḥᵃmûšîm</em> — the horses are described as &#8220;bred from the royal stud&#8221; (or &#8220;royal relay horses&#8221;); the exact meaning is debated, but the emphasis is on speed. The royal courier system (<em>ʾāḥaštᵉrānîm</em>) was the Persian imperial postal service, the fastest communication network in the ancient world; Herodotus describes it admiringly. The counter-decree travels with maximum urgency, mirroring and countering the urgency of the original decree in 3:15.</p>",
    "11": "<p>The counter-decree grants the Jews &#8220;the right to assemble and defend their lives&#8221; — <em>lᵉhiqqāhēl ûlᵉʿamōḏ ʿal-napšām</em> — and to destroy, kill, and annihilate (<em>lᵉhašmîḏ lahᵃrōḡ ûlᵉʾabbēḏ</em>) any armed force that attacks them, including women and children, and to plunder their property. The permission to take plunder mirrors what the original decree authorized against the Jews (3:13) — the counter-decree is a structural mirror image of the original. Notably, the Jews will not take the plunder (9:10, 15, 16), distinguishing their warfare from that of their attackers.</p>",
    "12": "<p>The timing — the thirteenth day of Adar — is the date Haman had selected by pur (lot) in 3:7. The counter-decree specifies the same date as the original; rather than postponing the crisis, it transforms it on the same day into a test of who will attack and who will defend. The providence of pur-reversal reaches its logical conclusion: the day of death becomes the day of deliverance.</p>",
    "13": "<p>&#8220;A copy of the document was to be issued as law (<em>dāṯ</em>) in every province, publicly announced to all peoples, so that the Jews would be ready on that day to avenge themselves on their enemies.&#8221; The word <em>dāṯ</em> is a Persian loanword (cognate with Avestan <em>dāta</em>, law/decree) used throughout Esther and Daniel for imperial legal pronouncements. Its use here emphasizes that the counter-decree has the same legal force as the original — not a special exception but a standing royal law.</p>",
    "14": "<p>The couriers depart &#8220;urgently, pressed on by the king&#8217;s command&#8221; — the same urgency as 3:15 where the first decree was dispatched. The decree arrives in Susa simultaneously with its proclamation, meaning the capital and the provinces receive word together. The deliberate mirroring of the original dispatch process signals that this is a legally equivalent counter-decree, not merely a royal wish.</p>",
    "15": "<p>Mordecai leaves the king&#8217;s presence wearing <em>lᵉḇûš malkûṯ tᵉkelēṯ wāḥûr</em> — royal garments of blue and white — with a large golden crown (<em>ʿᵃṭeret zāhāḇ gᵉḏôlāh</em>) and a fine linen cloak (<em>taʿᵃṭep bûṣ wᵉʾargāmān</em>). Blue and white are Persian royal colors; the combination of crown, robe, and cloak represents full royal investiture. Mordecai in chapter 4 wore sackcloth; Mordecai in chapter 8 wears the full apparatus of royal authority. The city of Susa shouts in joy — the same city that was in confusion after the first decree (3:15) now rejoices.</p>",
    "16": "<p><em>Layyᵉhûḏîm hāyᵉṯāh ʾôrāh wᵉśimḥāh wᵉśāśōn wîqār</em> — &#8220;For the Jews there was light and gladness, joy and honor.&#8221; The four-word formula of complete well-being is a stylistic marker of total reversal; the tetrad matches the fourfold negation implicit in 4:1-3 (darkness, mourning, weeping, shame). In the liturgy of Havdalah (the Jewish ceremony separating Sabbath from the week), this verse is traditionally quoted — suggesting its early reception as a declaration of salvific reversal.</p>",
    "17": "<p><em>Miṯyahadîm</em> — &#8220;declared themselves Jews&#8221; — is a unique denominalization, the first attested use of a verb meaning &#8220;to become/act as a Jew.&#8221; The motivation is <em>pāḥaḏ hayyᵉhûḏîm nāpal ʿᵃlêhem</em> — &#8220;the fear of the Jews fell upon them&#8221; — which echoes the Holy War formula of divine terror preceding Israel&#8217;s victories (cf. Exod 15:16; Deut 11:25). Whether these conversions were sincere or opportunistic, the narrator notes them without judgment; the theological resonance with Ruth&#8217;s covenant loyalty and the inclusion of foreigners under YHWH&#8217;s protection is present in the background.</p>"
  },
  "9": {
    "1": "<p>&#8220;On the thirteenth day of the twelfth month — the month of Adar&#8221; — the date Haman had selected by pur (lot) in 3:7, casting lots from the first month (Nisan) to find the most auspicious date for destroying the Jews. The reversal is not merely that the Jews survive but that the very date chosen by supernatural divination for their destruction becomes the date of their enemies&#8217; destruction. The pur has been turned — not cancelled but inverted by YHWH&#8217;s hidden governance.</p>",
    "2": "<p>The Jews assemble in their cities throughout the provinces &#8220;to strike at those who sought their harm.&#8221; <em>Wᵉʾîš lōʾ-ʿāmaḏ bipᵉnêhem</em> — &#8220;and no one could stand against them&#8221; — echoes Deuteronomy 11:25: &#8220;No one shall be able to stand against you.&#8221; The military-theological language of covenant warfare is invoked: the enemies of God&#8217;s people are unable to withstand them when YHWH acts on their behalf, even in a narrative that never names him.</p>",
    "3": "<p>Provincial officials, satraps, and governors support the Jews because <em>pāḥaḏ mŏrᵃḏᵃkay nāpal ʿᵃlêhem</em> — &#8220;the dread of Mordecai had fallen upon them.&#8221; The Holy War formula of divine terror (cf. Gen 35:5; Exod 15:16; Josh 2:9) is here attributed to Mordecai rather than directly to God — consistent with the book&#8217;s theological method of attributing the divine action to human instruments. The officials who enforced the first decree now assist in reversing its effects.</p>",
    "4": "<p>Mordecai&#8217;s greatness in the palace is now empire-wide: <em>kî-gāḏôl mŏrᵃḏᵃkay bêṯ hammelek</em> — his reputation spreads as his authority grows. The man who sat at the gate in sackcloth (4:1) now exercises imperial-level power. The narrative draws a deliberate parallel to Joseph (Gen 41:40-43) and Daniel (Dan 2:48-49): the faithful Jew who refused to compromise rises from danger to power as an instrument of his people&#8217;s preservation.</p>",
    "5": "<p>&#8220;The Jews struck down all their enemies with the sword — killing, destroying, and doing as they pleased (<em>kᵉriṣônām</em>) with those who hated them.&#8221; The phrase &#8220;doing as they pleased&#8221; echoes Haman&#8217;s ambition: his genocidal plan was to do &#8220;as seems good (<em>kᵉṭôḇ</em>) to you&#8221; (3:11). The reversal is complete: what Haman was authorized to do to the Jews is what the Jews are now authorized to do to their attackers — but they will notably not take the plunder.</p>",
    "6": "<p>In Susa the citadel (<em>bᵉšûšan habîrāh</em>), five hundred men are killed. The capital city — site of Haman&#8217;s decree, Esther&#8217;s intercession, Mordecai&#8217;s public humiliation and exaltation — is the primary locus of both the threat and its reversal. The number is not symbolic but historical: the narrative records specific figures to ground the events in real administration of Ahasuerus&#8217;s empire.</p>",
    "7": "<p>The ten sons of Haman are named individually — Parshandatha, Dalphon, Aspatha — beginning the formal death record that runs through verses 7-9. Their names are Elamite or Persian compound names; scholarly analysis of the names suggests they are authentic Persian-period onomastics rather than symbolic inventions. The killing of Haman&#8217;s sons is the completion of the Agagite/Amalekite eradication that Saul failed to accomplish in 1 Samuel 15.</p>",
    "8": "<p>Poratha, Adalia, Aridatha — the list continues. Ancient Hebrew manuscripts and the Masoretic text write these ten names in a distinctive vertical or extended format, one name per line, to indicate their deaths in a single encounter (analogous to a casualty list). The typographic convention signals that these are not incidental casualties but the formal terminus of the Haman/Agagite line that the narrative has identified as the existential threat.</p>",
    "9": "<p>Parmashta, Arisai, Aridai, and Vajezatha — the final four sons. All ten sons dead, all ten named. The completeness of the list — no survivors, no heirs — closes the Agagite lineage that opened with Haman&#8217;s introduction in 3:1. The narrative has been structured from the beginning toward this terminus: the failure at 1 Samuel 15 is answered here with thorough completion.</p>",
    "10": "<p>&#8220;The ten sons of Haman son of Hammedatha, the enemy of the Jews — they killed. But they laid no hand on the plunder (<em>ûbabizzāh lōʾ šālᵉḥû ʾeṯ-yāḏām</em>).&#8221; This is the first of three statements that the Jews did not take plunder (repeated in 9:15 and 9:16). The restraint contrasts with Saul&#8217;s failure in 1 Samuel 15:19 (&#8220;Why did you not obey the voice of the LORD? Why did you pounce on the spoil?&#8221;). The Jews here demonstrate the covenantal discipline that their ancestor-king lacked; the Agagite threat that Saul&#8217;s greed allowed to persist is now terminated without the same moral compromise.</p>",
    "11": "<p>The number of killed in Susa is reported to the king on the same day — demonstrating both the efficiency of Persian administrative communication and the king&#8217;s continuing oversight of events. The report comes to him without Esther making the request; the king is informed as a matter of protocol and then turns to ask Esther whether she has any further requests.</p>",
    "12": "<p>The king reports to Esther: five hundred killed in Susa, the ten sons hanged. His question — &#8220;What is your request? It shall be given to you. What more is your petition? It shall be granted.&#8221; — repeats the formulaic offer of 5:3, 6, and 7:2 for the fourth time. Each repetition has escalated: Esther&#8217;s request here will be for an additional day of defensive action in Susa and the public hanging of Haman&#8217;s sons on the gallows.</p>",
    "13": "<p>Esther&#8217;s request for an additional day in Susa reflects the practical reality that Haman&#8217;s allies and those who had organized to attack the Jews required more than one day to be neutralized in the capital. The request to hang the ten sons&#8217; bodies on the gallows — they had already been killed — is a public legal declaration of their guilt and a deterrent warning; ancient Near Eastern practice displayed executed enemies publicly (cf. Josh 8:29, 10:26).</p>",
    "14": "<p>The decree is issued in Susa for the additional day; the ten sons are hanged. The narrative economy of verse 14 — two sentences for two actions — reflects that the legal and practical matters are settled. The additional day (the fourteenth of Adar in Susa vs. the thirteenth in the provinces) creates the structural basis for the two-day Purim observance: Susa celebrates on the fifteenth, the provinces on the fourteenth.</p>",
    "15": "<p>The Jews in Susa gather on the fourteenth of Adar and kill three hundred more men — again without taking plunder. The restraint is reiterated (<em>ûbabizzāh lōʾ šālᵉḥû ʾeṯ-yāḏām</em>) for the second time, reinforcing the covenantal pattern established in verse 10. The three hundred killed are those who had continued their attack after the first day; the additional day was not aggression but completion of defense.</p>",
    "16": "<p>The Jews throughout the provinces kill seventy-five thousand of those who hated them (<em>bᵉśōnᵉʾîhem</em>) — the enemies of the Jewish people who had organized to attack them under the first decree. The plunder restraint is stated a third time. The total of seventy-five thousand across the empire reflects the scale of anti-Jewish organization that had been enabled by Haman&#8217;s decree over the nine-month period since its issuance. The number is explicitly noted as not accompanied by plunder, completing the triadic emphasis on covenantal restraint.</p>",
    "17": "<p>The provinces celebrate on the fourteenth of Adar because their battle concluded on the thirteenth — they rested on the fourteenth and made it a day of feasting and gladness (<em>yôm mišᵉteh wᵉśimḥāh</em>). The spontaneous festivity precedes formal institution: the community&#8217;s natural response to deliverance creates the practice that Mordecai will subsequently codify. The celebration arises from experience before it is legislated — a pattern repeated in the institution of Passover, Pentecost, and other festivals.</p>",
    "18": "<p>The Jews in Susa celebrated on the fifteenth of Adar because they had assembled on both the thirteenth and fourteenth. The two-day battle creates a two-day celebration. This differential — fourteenth for the provinces, fifteenth for Susa — is the calendrical basis for the distinction between &#8220;Purim of the villages&#8221; (observed on the fourteenth) and &#8220;Purim of the walled cities&#8221; (observed on the fifteenth) in later Jewish law, where cities surrounded by walls in the time of Joshua observe on the fifteenth in honor of Susa.</p>",
    "19": "<p>The verse explicitly accounts for the ongoing practice: provincial Jews observe the fourteenth as &#8220;a day of gladness and feasting, a holiday, and sending portions (<em>ûmišᵉlôaḥ māānôṯ</em>) to one another.&#8221; The <em>mānôṯ</em> (portions/gifts of food) exchanged between neighbors becomes one of the defining practices of Purim observance — the communal sharing of the victory&#8217;s abundance. The practice is embedded in the observance before Mordecai&#8217;s letter formalizes it.</p>",
    "20": "<p>Mordecai records the events and sends letters to all the Jews throughout the empire. The shift from oral community practice to written codification is significant: the diaspora community&#8217;s religious life increasingly depended on textual transmission rather than temple presence or prophetic address. Mordecai&#8217;s letter becomes the charter document for an ongoing practice — the first festival instituted by written communal decree rather than Mosaic Torah command.</p>",
    "21": "<p>The establishment of Purim on the fourteenth and fifteenth of Adar every year creates a perpetual calendar anchor. <em>Lᵉqayyēm ʿᵃlêhem</em> — &#8220;to establish upon them&#8221; — is the legislative language of covenant obligation; the community accepts a binding annual observance. The two-day structure honors both the provincial (fourteenth) and capital (fifteenth) experiences, maintaining the historical specificity of the original events in the festival&#8217;s calendar form.</p>",
    "22": "<p>&#8220;As the days on which the Jews gained relief (<em>nāḥû</em>) from their enemies, and the month that was turned (<em>nehpak</em>) for them from sorrow into gladness and from mourning into a holiday.&#8221; The verb <em>nehpak</em> (turned/overturned) is the key theological word of the book: the pur that Haman cast to determine the day of destruction has been overturned into a day of deliverance. The festival commemorates not just the event but the turning — the divine reversal of what the enemy intended.</p>",
    "23": "<p>The community accepts what it had already begun to practice — the formal establishment of Purim ratifies an existing communal observance rather than imposing a new one. This pattern of legal codification following lived practice is consistent with other diaspora religious developments: practice precedes law; experience generates tradition; tradition is then ratified by communal authority. The consent structure here anticipates the rabbinic concept of <em>minhag</em> (custom) as a binding practice.</p>",
    "24": "<p><em>Pûr hûʾ haggôrāl</em> — &#8220;the pur — that is, the lot.&#8221; The narrator pauses to explicitly gloss the Persian word <em>pûr</em> with the Hebrew <em>gôrāl</em> (lot), explaining the festival&#8217;s name for readers unfamiliar with Elamite/Persian vocabulary. The lot that Haman cast to destroy is the lot that now names the festival of survival. The etymology of the festival name is embedded in the reversal narrative: the very linguistic marker of Haman&#8217;s scheme becomes the permanent memorial of its failure.</p>",
    "25": "<p>&#8220;But when she [Esther] came before the king, he ordered by letter that Haman&#8217;s evil scheme against the Jews should fall back on his own head, and that he and his sons should be hanged on the gallows.&#8221; The summary in verse 25 is a condensed retelling of chapters 7-8, functioning as the official narrative of the decree reversal — the version that would be read in the Purim letter and transmitted to future generations. The passive &#8220;it was ordered&#8221; attributes the reversal to royal authority while the reader understands the providential agency behind it.</p>",
    "26": "<p>The festival is named <em>Pûrîm</em> — the Hebrew plural of the Persian/Elamite singular <em>pûr</em>. The combination of &#8220;everything written in this letter, and what they had witnessed, and what had come to them&#8221; establishes a three-source basis for Purim observance: the written record, direct experience, and received tradition. The basis of the festival is both documentary and experiential — a model for diaspora memory-formation that does not depend on physical presence at a sanctuary.</p>",
    "27": "<p>&#8220;The Jews established and accepted (<em>qibbᵉlû wᵉqibbēl</em>) for themselves, for their descendants, and for all who joined their community.&#8221; The phrase <em>kol-hannilwîm ʿᵃlêhem</em> — &#8220;all who had joined themselves to them&#8221; — includes proselytes and gentile sympathizers in the Purim obligation; the festival is not ethnically exclusive but extends to all who identify with the Jewish community. The verb <em>qibbᵉlû</em> (accepted/received) is the same root used for receiving Torah tradition — Purim observance is placed in the category of received communal obligation.</p>",
    "28": "<p>&#8220;These days were to be remembered (<em>nizkarim</em>) and kept in every generation, every family, every province, and every city.&#8221; The fourfold &#8220;every&#8221; (<em>kol-dôr wāḏôr kol-mišpāḥāh kol-mᵉḏînāh ûmᵉḏînāh kol-ʿîr wāʿîr</em>) emphasizes the universality of the obligation across time, kinship, geography, and settlement. The command to remember (<em>zakōr</em>) connects Purim to the Deuteronomic memory imperative that structures Israelite covenant theology — the festival preserves the event against the amnesia that endangers covenant fidelity.</p>",
    "29": "<p>Queen Esther daughter of Abihail writes with Mordecai — with &#8220;full authority (<em>tōqep</em>)&#8221; — to confirm the second Purim letter. <em>Tōqep</em> is a Persian loanword meaning force/authority/power, used of royal strength in 10:2. Esther exercises legislative authority in her own right alongside Mordecai; the woman who had hidden her identity (2:10) now signs official imperial correspondence under her own name and lineage. The book ends with Esther as co-legislator of a permanent institution.</p>",
    "30": "<p>Mordecai sends letters to all the Jews in the hundred and twenty-seven provinces — the full extent of the empire — with words of <em>šālôm weʾĕmeṯ</em> (peace and truth/faithfulness). The combination echoes the Aaronic blessing (Num 6:24-26) and the covenant promises of Zechariah 8:19; the diaspora community receives an authoritative communal document that carries the weight of both royal and covenant authority.</p>",
    "31": "<p>The Purim observance is confirmed &#8220;as Mordecai the Jew and Queen Esther had prescribed (<em>qiyyᵉmû ʿᵃlêhem</em>)&#8221; — and as they had accepted for themselves and their descendants regarding the fasts and their lamenting (<em>ṣārᵃḵêhem</em>). The reference to fasts associated with the Purim season suggests that the three-day fast of 4:16 was institutionalized as well — the days of fasting and mourning preceding Purim serve as the counterpart to the days of feasting and joy. The liturgical year encompasses both lament and celebration.</p>",
    "32": "<p>&#8220;The command of Esther confirmed these regulations of Purim, and it was recorded in the book.&#8221; The final verse of the chapter ends with <em>wᵉniktāḇ bassēper</em> — &#8220;and it was written in the book&#8221; — closing the legislation with a citation of its written form. The book of Esther is itself the book referenced: the megillah (scroll) read annually at Purim is the record that confirms the institution. The narrative closes on its own textual authority — the scroll that documents the events is the foundation of the practice it describes.</p>"
  },
  "10": {
    "1": "<p>The epilogue returns to the imperial frame: Ahasuerus imposes tribute (<em>mas</em>) on the land and the islands of the sea (<em>ʾiyyê hayyām</em>). The imperial business continues; the Persian empire did not change its character because the Jews were preserved within it. The reference to tribute is not incidental — it establishes that Mordecai&#8217;s position exists within the ongoing structures of Persian power, not in a transformed political order. The book ends in the real world of empire, not in an eschatological resolution.</p>",
    "2": "<p>&#8220;All the acts of the king&#8217;s power (<em>tōqep</em>) and strength (<em>gᵉḇûrāh</em>), and the full account of the greatness of Mordecai (<em>gᵉḏullat mŏrᵃḏᵃkay</em>) to which the king advanced him (<em>giḏḏᵉlô hammelek</em>) — are they not written in the book of the chronicles of the kings of Media and Persia?&#8221; The official Persian chronicles that recorded Mordecai&#8217;s forgotten service in 6:1-3 now record his greatness; the same archive that nearly failed him becomes the permanent register of his honor. The phrase &#8220;the book of the chronicles of the kings of Media and Persia&#8221; is the exact archive cited in Ezra 4:15 and 6:2 — a historically verifiable imperial record.</p>",
    "3": "<p>&#8220;For Mordecai the Jew was second only to King Ahasuerus (<em>mišneh lammelek ʾᵃḥašwērôš</em>) and great among the Jews, beloved by the multitude of his people (<em>rāṣûy lᵉrōḇ ʾeḥāyw</em>), seeking the good of his people (<em>dōrēš ṭôḇ lᵉʿammô</em>) and speaking peace to all his descendants.&#8221; The phrase <em>mišneh lammelek</em> (second to the king) is the exact position held by Joseph (Gen 41:40 — <em>ʿal-kol-ʿammî yiššaq</em>) and by Daniel (Dan 5:29 — <em>taltî bᵉmalkûtāʾ</em>). The diaspora ideal — the faithful Jew who rises to the second rank in a pagan court and uses that position for the welfare of his people — reaches its most complete formulation here. <em>Dōrēš ṭôḇ lᵉʿammô</em> — seeking the good of his people — is the covenant leader&#8217;s vocation, last used in this sense for Israel&#8217;s ideal kings in the Psalms and Prophets.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'esther')
    merge_comm(existing, ESTHER)
    save_comm('mkt-context', 'esther', existing)
    print('Esther 6-10 mkt-context written.')

if __name__ == '__main__':
    main()
